import React, { useState } from 'react';
import PropTypes from 'prop-types';
import CssBaseline from '@material-ui/core/CssBaseline';
import Paper from '@material-ui/core/Paper';
import Container from '@material-ui/core/Container';
import Typography from '@material-ui/core/Typography';
import Divider from '@material-ui/core/Divider';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import { makeStyles } from '@material-ui/core/styles';
import SearchAndFilterBoats from './searchandfilterboats';
import BoatCards from './boatcards';
import BoatsForSaleIntro from './boatsforsaleintro';
import BoatRegisterIntro from './boatregisterintro';

const useStyles = makeStyles((theme) => ({
  root: {
    display: 'flex',
  },
  content: {
    flexGrow: 1,
    padding: theme.spacing(3),
  },
  menuButton: {
    marginRight: theme.spacing(2),
    [theme.breakpoints.up('sm')]: {
      display: 'none',
    },
  },
}));

function Intro({boatsForSale}) {
  if (boatsForSale) {
    return (<BoatsForSaleIntro/>)
  }
  return (<BoatRegisterIntro/>);
}

function BrowseBoats({ pickers, options }) {
  const classes = useStyles();
  const [state, setState] = useState({ 
    page: 1,
    boatsPerPage: '12',
    sortField: 'name',
    sortDirection: 'asc',
    filters:{ 
      year: { firstYear: 1800, lastYear: new Date().getFullYear() },
      sale: (options === 'forsale'),
      nopics: (options === 'forsale'),
    },    
   });

  //const [mobileOpen, setMobileOpen] = useState(false);
  //const handleDrawerToggle = () => {
  //  setMobileOpen(!mobileOpen);
  //};

  const blank = "_blank";

  return (
    <div className={classes.root}>
      <CssBaseline />
      {/*
      <LeftMenu open={mobileOpen} onClose={handleDrawerToggle} 
        container={window ? () => window().document.body : undefined} />
      */}
      <Paper>
        {/*
        <Grid container direction="row">
          <DrawerController onClick={handleDrawerToggle}/>
        </Grid>
        */}
        <Container>
          <Intro boatsForSale={state.filters.sale} />
        <SearchAndFilterBoats
          sortDirection={state.sortDirection}
          sortField={state.sortField}
          boatsPerPage={state.boatsPerPage}
          filters={state.filters}
          onPageSizeChange={(boatsPerPage) => setState({ ...state, boatsPerPage })}
          onSortFieldChange={(sortField) => setState({ ...state, sortField })}
          onSortDirectionChange={(event) => {
              const sortDirection = event.target.checked ? 'desc' : 'asc';
              setState({ ...state, sortDirection });
            }
          }
          onFilterChange={(filters) => setState({ ...state, filters })}
          pickers={pickers}
        />
        </Container>
        <Divider />
        <BoatCards
          boatsPerPage={parseInt(state.boatsPerPage)}
          sortField={state.sortField}
          sortDirection={state.sortDirection}
          filters={state.filters}
          onPageChange={(page) => setState({ ...state, page })}
        />
        <Divider />
        <Typography>
        Other great places to look for boats are:
        </Typography>
          <List>
            <ListItem>
            <Typography>
              <a target={blank} href="https://www.nationalhistoricships.org.uk">
                National Historic Ships
              </a>
              </Typography>
            </ListItem>
            <ListItem>
            <Typography>
              <a target={blank} href="https://nmmc.co.uk/explore/databases/">NMM Cornwall</a>&nbsp;
              maintain a number of interesting databases including small boats and
              yacht designs
              </Typography>
            </ListItem>
          </List>
      </Paper>
    </div>
  );
}

BrowseBoats.propTypes = {
  /**
   * Injected by the documentation to work in an iframe.
   * You won't need it on your project.
   */
  window: PropTypes.func,
};
export default BrowseBoats;
